                           dc:issued        "2020-01-01"^^xsd:date ;
                           dc:valid         "2030-12-31"^^xsd:date ;
                           ogc:hasGeometry  [ rdf:type   ogc:Geometry ;
                                              ogc:asWKT  "POINT(4.4026 51.2195)"^^ogc:wktLiteral
                                            ]
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  dc:created ;
                                             hydra:required  true ;
