:Observation  rdf:type   owl:Class ;
        rdfs:comment     "An observation is a measurement or observation that was performed at a measurement point."@en ;
        rdfs:label       "Observation"@en ;
        rdfs:subClassOf  sosa:Observation ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An observation must have a result."@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      sosa:hasResult ;
                           owl:someValuesFrom  sosa:Result
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An observation must be linked to exactly one measurement point or installation"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      sosa:hasFeatureOfInterest ;
                           owl:someValuesFrom  :Emission
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  :localId ;
                                             hydra:required  true ;
                                             hydra:variable  "uuid"
                                           ] ;
                           hydra:template  "https://example.org/id/observatie/{uuid}"^^hydra:Rfc6570Template
                         ] .

:section  rdf:type    owl:ObjectProperty ;
        rdfs:comment  "The VLAREM section that applies to a process or installation."@en ;
        rdfs:domain   [ rdf:type      owl:Class ;
                        rdfs:comment  "The VLAREM section can apply to processes"@en ;
                        owl:unionOf   ( :Installation )
                      ] ;
        rdfs:label    "VLAREM Section"@en ;
        rdfs:range    :Section .

:TransportProcedure  rdf:type  skos:Concept , owl:Class ;
        rdfs:comment     "A transport procedure is a specific procedure that relates to the transport of substances within or outside a process."@en ;
        rdfs:label       "Transport Procedure"@en ;
        rdfs:subClassOf  sosa:Procedure .

:gesloten  rdf:type           skos:Concept , adms:Status ;
        rdfs:comment          "The closed status indicates that an entity has been permanently taken out of service."@en ;
        rdfs:equivalentClass  <http://purl.org/adms/status/Withdrawn> ;
        rdfs:label            "Closed"@en ;
        skos:prefLabel        "Closed"@en .

[ rdf:type            owl:Class ;
  rdfs:comment        "A process with an emission procedure must release or discharge substances at an emission point"@en ;
  rdfs:subClassOf     [ rdf:type            owl:Restriction ;
                        owl:onProperty      ssn:implementedBy ;
                        owl:someValuesFrom  :Emissionpunt
                      ] ;
  owl:intersectionOf  ( :Process
                        [ rdf:type            owl:Restriction ;
                          owl:someValuesFrom  :EmissionProcedure
                        ]
                      )
] .

:ProcessVariable  rdf:type  owl:Class ;
        rdfs:comment     "A process variable is a variable data that serves as input or output of a process."@en ;
        rdfs:label       "Process Variable"@en ;
        rdfs:subClassOf  pplan:Variable ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
